const raw = $.steps.fetchFile.output || '';
const lines = raw.split('\n');
const lineCount = lines.length;
const charCount = raw.length;
const preview = lines.slice(0, 5).join('\n');
const truncated = raw.slice(0, 40000);

return { rawData: truncated, lineCount, charCount, preview, fileUrl: $.input.fileUrl };

const d = $.steps.prepareData.output;
const goal = $.input.analysisGoal || 'Summarize the data, identify key patterns, and highlight notable values';

let prompt = 'You are a data analyst. Analyze the following file data fetched from: ' + d.fileUrl + '

';
prompt += 'ANALYSIS GOAL: ' + goal + '

';
prompt += 'FILE STATS: ' + d.lineCount + ' lines, ' + d.charCount + ' characters
';
prompt += 'PREVIEW (first 5 lines):
' + d.preview + '

';
prompt += 'FULL DATA:
' + d.rawData + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Identify the data format (CSV, JSON, TSV, etc.)
';
prompt += '- Extract key fields/columns and summarize what the data contains
';
prompt += '- Identify patterns, outliers, or notable values
';
prompt += '- Provide actionable insights based on the analysis goal
';
prompt += '- Use Slack mrkdwn formatting: *bold* (NOT **bold**), _italic_, numbered lists

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "dataFormat": "CSV|JSON|TSV|text",
';
prompt += '  "recordCount": 0,
';
prompt += '  "fields": ["field1", "field2"],
';
prompt += '  "summary": "overview of the data",
';
prompt += '  "keyFindings": ["finding 1", "finding 2"],
';
prompt += '  "insights": "actionable insights based on the analysis goal",
';
prompt += '  "sampleRecords": "formatted sample of 3-5 representative records"
';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, dataFormat: 'unknown', recordCount: 0, fields: [], keyFindings: [], insights: '', sampleRecords: '' }; }

const ai = $.steps.parseAI.output;
const d = $.steps.prepareData.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'File Data Analysis', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Source:* ' + d.fileUrl + '\n*Format:* ' + (ai.dataFormat || 'unknown') + ' | *Records:* ' + (ai.recordCount || d.lineCount) + ' | *Fields:* ' + (ai.fields || []).join(', ') } });
blocks.push({ type: 'divider' });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary*\n' + ai.summary.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

if (ai.keyFindings && ai.keyFindings.length > 0) {
  let findingsText = '*Key Findings*\n';
  ai.keyFindings.forEach((f, i) => { findingsText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: findingsText.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

if (ai.insights) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Insights*\n' + ai.insights.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

if (ai.sampleRecords) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Sample Records*\n' + ai.sampleRecords.slice(0, 2900) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Analyzed with Claude AI | One CLI' }] });

const fallback = 'File Analysis: ' + (ai.dataFormat || '') + ' with ' + (ai.recordCount || d.lineCount) + ' records - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallback };
